import React, { useState } from 'react';
import { GameState, ClanMember, Region, Realm, Building, Inventory, SpecializedTalents } from './types';
import { INITIAL_MEMBERS, INITIAL_REGIONS, REALM_ORDER, BUILDING_TYPES } from './constants';
import { CLAN_MASTER_REGISTRY } from './data/master_registry';
import ClanDashboard from './components/ClanDashboard';
import WorldMap from './components/WorldMap';
import ClanManagement from './components/ClanManagement';
import { generateYearlyEvent } from './services/geminiService';

const App: React.FC = () => {
    const [state, setState] = useState<GameState>({
        year: 1,
        spiritStones: CLAN_MASTER_REGISTRY.spiritStones,
        merit: CLAN_MASTER_REGISTRY.merit,
        luck: CLAN_MASTER_REGISTRY.luck,
        members: INITIAL_MEMBERS,
        regions: INITIAL_REGIONS,
        buildings: [],
        inventory: CLAN_MASTER_REGISTRY.inventory,
        currentRegionId: '',
        isMirrorActive: false,
        logs: ["太平历初，望月李氏在此立基。昊天镜悬于祠堂，照破虚妄。"],
        heritagePool: CLAN_MASTER_REGISTRY.heritagePool,
    });

    const [event, setEvent] = useState<any>(null);
    const [isProcessing, setIsProcessing] = useState(false);
    const [isDashboardVisible, setIsDashboardVisible] = useState(true);
    const [isManagementVisible, setIsManagementVisible] = useState(false);
    const [isConsoleCollapsed, setIsConsoleCollapsed] = useState(false);

    const handleUpdateMember = (id: string, updates: Partial<ClanMember>) => {
        setState(prev => {
            let updatedMembers = [...prev.members];
            if (updates.position === '家主') {
                updatedMembers = updatedMembers.map(m => 
                    (m.position === '家主' && m.id !== id) ? { ...m, position: '长老' } : m
                );
            }
            if (updates.position === '老祖') {
                updatedMembers = updatedMembers.map(m => 
                    (m.position === '老祖' && m.id !== id) ? { ...m, position: '长老' } : m
                );
            }
            return {
                ...prev,
                members: updatedMembers.map(m => m.id === id ? { ...m, ...updates } : m)
            };
        });
    };

    const handleUpdateBuilding = (id: string, updates: Partial<Building>) => {
        setState(prev => ({
            ...prev,
            buildings: prev.buildings.map(b => b.id === id ? { ...b, ...updates } : b)
        }));
    };

    const handleAddBuilding = (type: string) => {
        const info = BUILDING_TYPES[type];
        if (state.spiritStones < info.baseCost) return;

        const newBuilding: Building = {
            id: `b_${Date.now()}`,
            type,
            level: 1,
            assignedMemberId: null,
            isFinished: false,
            turnsRemaining: info.baseTurns
        };

        setState(prev => ({
            ...prev,
            spiritStones: prev.spiritStones - info.baseCost,
            buildings: [...prev.buildings, newBuilding],
            logs: [`【营建】族中开始营造 ${info.name}，预计耗时 ${info.baseTurns} 载。`, ...prev.logs].slice(0, 30)
        }));
    };

    const handleAssignBuilding = (buildingId: string, memberId: string | null) => {
        setState(prev => ({
            ...prev,
            buildings: prev.buildings.map(b => {
                if (b.id === buildingId) {
                    return { ...b, assignedMemberId: memberId };
                }
                if (memberId !== null && b.assignedMemberId === memberId) {
                    return { ...b, assignedMemberId: null };
                }
                return b;
            })
        }));
    };

    const handleNextYear = async () => {
        setIsProcessing(true);
        let yearLogs: string[] = [];
        let stoneGain = 50; 
        let meritGain = 2;
        let bonusInventory: Inventory = { herbs: {}, minerals: {}, paper: 0, pills: {}, weapons: {}, methods: {}, scrolls: {} };

        const updatedBuildings = state.buildings.map(b => {
            let nb = { ...b };
            if (!nb.isFinished) {
                const remaining = nb.turnsRemaining - 1;
                if (remaining <= 0) {
                    yearLogs.push(`【营建】${BUILDING_TYPES[nb.type].name} 终于落成！`);
                    nb = { ...nb, isFinished: true, turnsRemaining: 0 };
                } else {
                    nb = { ...nb, turnsRemaining: remaining };
                }
            } else {
                if (nb.activeProduction) {
                    const rem = nb.activeProduction.turnsRemaining - 1;
                    if (rem <= 0) {
                        const { recipeName, type } = nb.activeProduction;
                        yearLogs.push(`【产出】${BUILDING_TYPES[nb.type].name} 顺利完成了 ${recipeName} 的${type === 'Alchemy' ? '炼制' : '打造'}！`);

                        if (type === 'Alchemy') {
                            bonusInventory.pills[recipeName] = (bonusInventory.pills[recipeName] || 0) + 1;
                        } else {
                            bonusInventory.weapons[recipeName] = (bonusInventory.weapons[recipeName] || 0) + 1;
                        }

                        nb.activeProduction = undefined;
                    } else {
                        nb.activeProduction = { ...nb.activeProduction, turnsRemaining: rem };
                    }
                }
            }

            if (nb.isFinished) {
                if (nb.type === 'Market' && nb.assignedMemberId) stoneGain += 200;
                if (nb.type === 'SpiritField') {
                    bonusInventory.herbs["灵谷草"] = (bonusInventory.herbs["灵谷草"] || 0) + 5;
                }
            }
            return nb;
        });

        const memberStatusChanges: Record<string, Partial<ClanMember>> = {};

        const updatedRegions = state.regions.map(r => {
            let nr = { ...r };

            if (nr.owner === '望月李氏' && nr.production) {
                if (nr.production.stones) stoneGain += nr.production.stones;
                if (nr.production.merit) meritGain += nr.production.merit;
                if (nr.production.items) {
                    Object.entries(nr.production.items).forEach(([name, count]) => {
                        if (nr.type === 'field') bonusInventory.herbs[name] = (bonusInventory.herbs[name] || 0) + count;
                        else if (nr.type === 'mine') bonusInventory.minerals[name] = (bonusInventory.minerals[name] || 0) + count;
                    });
                }
            }

            if (nr.activeMission) {
                const rem = nr.activeMission.turnsRemaining - 1;
                if (rem <= 0) {
                    const member = state.members.find(m => m.id === nr.activeMission!.memberId);
                    if (member) {
                        const mType = nr.activeMission.type;
                        const memberPower = REALM_ORDER.indexOf(member.realm) * 10 + member.subRealm;
                        const diff = nr.difficulty;

                        let riskSuccess = true;
                        if (memberPower < diff) {
                            const riskFactor = (diff - memberPower) / 10; 
                            const roll = Math.random();
                            if (roll < riskFactor * 0.2) {
                                memberStatusChanges[member.id] = { status: 'dead', deathYear: state.year };
                                yearLogs.push(`【讣闻】${member.name} 在执行 ${nr.name} 任务时不幸陨落。`);
                                riskSuccess = false;
                            } else if (roll < riskFactor * 0.8) {
                                memberStatusChanges[member.id] = { status: 'injured' };
                                yearLogs.push(`【伤情】${member.name} 强闯 ${nr.name}，虽保住性命但已身受重伤。`);
                                riskSuccess = false;
                            }
                        }

                        if (riskSuccess) {
                            if (mType === 'Occupy' || mType === 'War') {
                                nr.owner = '望月李氏';
                                yearLogs.push(`【版图】${member.name} 成功平定 ${nr.name}！`);
                            } else {
                                const rewardPool = nr.resources;
                                const reward = rewardPool[Math.floor(Math.random() * rewardPool.length)];
                                yearLogs.push(`【探查】${member.name} 从 ${nr.name} 带回了 ${reward}。`);
                                if (reward.includes('草') || reward.includes('花')) bonusInventory.herbs[reward] = (bonusInventory.herbs[reward] || 0) + 1;
                                else bonusInventory.minerals[reward] = (bonusInventory.minerals[reward] || 0) + 1; 
                            }
                        }
                    }
                    nr.activeMission = undefined;
                } else {
                    nr.activeMission = { ...nr.activeMission, turnsRemaining: rem };
                }
            }
            return nr;
        });

        const updatedMembers = state.members.map(m => {
            let nm = { ...m, ...(memberStatusChanges[m.id] || {}) };
            if (nm.status === 'dead') return nm;

            nm.age += 1;
            const hasRoots = (Object.values(nm.roots) as number[]).some(v => v > 0);

            if (nm.assignment === 'Cultivation' && hasRoots && nm.realm !== Realm.Mortal && nm.status === 'healthy') {
                nm.cultivationProgress += (nm.aptitude / 10) + 5;
                if (nm.cultivationProgress >= 100) {
                    if (nm.subRealm < 9) {
                        nm.cultivationProgress = 0;
                        nm.subRealm += 1;
                    } else {
                        // Keep progress at 100 for manual breakthrough at realm boundaries
                        nm.cultivationProgress = 100;
                    }
                }
            }

            if (nm.age >= nm.maxAge) {
                nm.status = 'dead'; nm.deathYear = state.year;
                yearLogs.push(`【陨落】族中长辈 ${nm.name} 寿元耗尽，与世长辞。`);
            }

            if (nm.assignment === 'Mission') {
                const missionRegion = updatedRegions.find(r => r.activeMission?.memberId === nm.id);
                if (!missionRegion) nm.assignment = 'Idle';
            }

            if (nm.status === 'injured' && nm.assignment === 'Idle') {
                if (Math.random() > 0.5) {
                    nm.status = 'healthy';
                    yearLogs.push(`【痊愈】${nm.name} 的伤势已经大好。`);
                }
            }

            return nm;
        });

        const newEvent = await generateYearlyEvent({ ...state, members: updatedMembers, regions: updatedRegions });

        setState(prev => {
            const finalHerbs = { ...prev.inventory.herbs };
            Object.entries(bonusInventory.herbs).forEach(([name, count]) => { finalHerbs[name] = (finalHerbs[name] || 0) + count; });
            const finalMinerals = { ...prev.inventory.minerals };
            Object.entries(bonusInventory.minerals).forEach(([name, count]) => { finalMinerals[name] = (finalMinerals[name] || 0) + count; });
            const finalPills = { ...prev.inventory.pills };
            Object.entries(bonusInventory.pills).forEach(([name, count]) => { finalPills[name] = (finalPills[name] || 0) + count; });
            const finalWeapons = { ...prev.inventory.weapons };
            Object.entries(bonusInventory.weapons).forEach(([name, count]) => { finalWeapons[name] = (finalWeapons[name] || 0) + count; });

            return {
                ...prev,
                year: prev.year + 1,
                members: updatedMembers,
                buildings: updatedBuildings,
                regions: updatedRegions,
                spiritStones: prev.spiritStones + stoneGain,
                merit: prev.merit + meritGain,
                inventory: { 
                    ...prev.inventory, 
                    herbs: finalHerbs, 
                    minerals: finalMinerals,
                    pills: finalPills,
                    weapons: finalWeapons
                },
                logs: [...yearLogs, ...prev.logs].slice(0, 30)
            };
        });
        setEvent(newEvent);
        setIsProcessing(false);
    };

    const handleUseHaotianMirror = () => {
        if (state.merit < 20) return;
        const undiscovered = state.regions.filter(r => !r.isDiscovered);
        if (undiscovered.length === 0) return;
        const reveal = undiscovered[Math.floor(Math.random() * undiscovered.length)];
        setState(prev => ({
            ...prev,
            merit: prev.merit - 20,
            regions: prev.regions.map(r => r.id === reveal.id ? { ...r, isDiscovered: true } : r),
            logs: [`【昊天镜】镜光贯穿虚空，照破了 ${reveal.name} 的迷雾！`, ...prev.logs].slice(0, 30)
        }));
    };

    const handleSelectRegion = (r: Region | null) => {
        if (r && r.id === 'li_clan_home') {
            setIsManagementVisible(true);
            setState(p => ({ ...p, currentRegionId: '' }));
        } else {
            setState(p => ({ ...p, currentRegionId: r ? r.id : '' }));
        }
    };

    return (
        <div className="h-full w-full flex flex-col bg-[#0f0a07] text-gray-300 overflow-hidden select-none font-serif">
            <header className="h-16 bg-[#2c1810] border-b-2 border-yellow-900/50 flex items-center justify-between px-8 z-40 shadow-xl shrink-0">
                <div className="flex items-center gap-12">
                    <h1 className="text-2xl font-cursive text-yellow-500 tracking-widest">玄鉴仙族：昊天纪元</h1>
                    <div className="flex gap-6 items-center border-l border-yellow-900/30 pl-8">
                        <div className="flex flex-col">
                            <span className="text-[10px] text-gray-500 uppercase">家族灵石</span>
                            <span className="text-lg font-mono text-yellow-400">✨ {state.spiritStones}</span>
                        </div>
                        <div className="flex flex-col">
                            <span className="text-[10px] text-gray-500 uppercase">族中功德</span>
                            <span className="text-lg font-mono text-blue-400">💠 {state.merit}</span>
                        </div>
                        <div className="flex flex-col">
                            <span className="text-[10px] text-gray-500 uppercase">天罡历载</span>
                            <span className="text-lg font-mono text-yellow-100">{state.year}</span>
                        </div>
                    </div>
                </div>
                <div className="flex items-center gap-4">
                    <button onClick={handleUseHaotianMirror} disabled={state.merit < 20} className="px-5 py-2 bg-gradient-to-r from-blue-900 to-indigo-900 border border-blue-400 text-blue-100 rounded-full text-xs font-bold hover:brightness-125 transition-all shadow-[0_0_15px_rgba(59,130,246,0.4)] disabled:opacity-30">🪞 昊天镜 (20功德)</button>
                    <button onClick={() => setIsManagementVisible(true)} className="px-5 py-2 bg-black/40 border border-orange-900 text-orange-500 rounded-full text-xs font-bold hover:bg-orange-900/20 transition-all">🏛️ 家族管理</button>
                    <button onClick={() => setIsDashboardVisible(!isDashboardVisible)} className={`px-5 py-2 rounded-full border transition-all text-xs font-bold ${isDashboardVisible ? 'bg-yellow-800 border-yellow-500 text-yellow-100' : 'bg-black/40 border-yellow-900 text-gray-500'}`}>📜 族谱</button>
                    <button onClick={handleNextYear} disabled={isProcessing || !!event} className="bg-gradient-to-b from-yellow-700 to-yellow-900 hover:from-yellow-600 hover:to-yellow-800 disabled:opacity-30 text-white px-8 py-2 rounded border-t border-yellow-500/30 border-b-4 border-black/50 font-bold transition-all text-sm shadow-lg">{isProcessing ? '推演中' : '岁过一载'}</button>
                </div>
            </header>

            <main className="flex-1 flex overflow-hidden relative">
                <div className="flex-1 relative bg-[#0a0705]">
                    <WorldMap 
                        regions={state.regions} 
                        members={state.members} 
                        currentRegionId={state.currentRegionId} 
                        onSelectRegion={handleSelectRegion} 
                        onUpdateMember={handleUpdateMember} 
                        onUpdateRegion={(id, u) => setState(p => ({ ...p, regions: p.regions.map(r => r.id === id ? { ...r, ...u } : r) }))} 
                    />

                    <div className={`absolute bottom-6 left-6 transition-all duration-500 parchment border-2 border-[#4a3728] rounded-sm shadow-2xl z-20 opacity-95 flex flex-col overflow-hidden ${isConsoleCollapsed ? 'w-48 h-10' : 'w-72 h-64'}`}>
                        <div className="flex justify-between items-center px-4 py-2 border-b border-[#4a3728]/30 bg-black/5 shrink-0 cursor-pointer" onClick={() => setIsConsoleCollapsed(!isConsoleCollapsed)}>
                            <span className="text-[11px] text-[#2c1810] font-bold uppercase tracking-widest font-cursive">族史摘要</span>
                            <button className="text-[#4a3728] hover:text-black transition-transform duration-300" style={{ transform: isConsoleCollapsed ? 'rotate(180deg)' : 'rotate(0deg)' }}>▼</button>
                        </div>
                        {!isConsoleCollapsed && (
                            <div className="flex-1 overflow-y-auto p-4 space-y-3 custom-scrollbar">
                                {state.logs.length > 0 ? state.logs.map((log, i) => (
                                    <p key={i} className="leading-relaxed text-black/80 font-serif font-bold text-[11px] border-b border-[#4a3728]/5 pb-1 animate-fade-in">
                                        <span className="text-[#8b0000] mr-2">◈</span> {log}
                                    </p>
                                )) : (
                                    <p className="text-gray-500 italic text-[10px] text-center py-10">暂无家族记载</p>
                                )}
                            </div>
                        )}
                    </div>
                </div>

                {isDashboardVisible && (
                    <div className="w-80 h-full border-l border-yellow-900/50 flex flex-col shrink-0">
                        <ClanDashboard state={state} onUpdateMember={handleUpdateMember} onAddMember={() => {}} />
                    </div>
                )}
            </main>

            {isManagementVisible && (
                <ClanManagement 
                    state={state} 
                    onUpdateMember={handleUpdateMember} 
                    onUpdateBuilding={handleUpdateBuilding}
                    onAddBuilding={handleAddBuilding} 
                    onAssignBuilding={handleAssignBuilding} 
                    onClose={() => setIsManagementVisible(false)} 
                />
            )}

            {event && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
                    <div className="bg-[#f4e4bc] w-full max-w-2xl p-8 rounded border-[12px] border-[#4a3728] shadow-2xl relative animate-scale-in">
                        <div className="absolute -top-10 left-1/2 -translate-x-1/2 bg-[#4a3728] text-yellow-500 px-10 py-3 rounded-b-xl font-cursive text-2xl">{event.title}</div>
                        <div className="text-[#2c1810] leading-relaxed text-lg font-serif italic mb-8 max-h-[40vh] overflow-y-auto custom-scrollbar pr-4">{event.content}</div>
                        <div className="grid grid-cols-2 gap-4">
                            <button onClick={() => setEvent(null)} className="p-4 border-2 border-[#4a3728]/40 rounded hover:bg-[#4a3728] group transition-all text-left">
                                <p className="font-bold text-[#2c1810] group-hover:text-yellow-400">{event.choiceA.text}</p>
                                <p className="text-[10px] text-gray-600 group-hover:text-yellow-100/60">{event.choiceA.effect}</p>
                            </button>
                            <button onClick={() => setEvent(null)} className="p-4 border-2 border-[#4a3728]/40 rounded hover:bg-[#4a3728] group transition-all text-left">
                                <p className="font-bold text-[#2c1810] group-hover:text-yellow-400">{event.choiceB.text}</p>
                                <p className="text-[10px] text-gray-600 group-hover:text-yellow-100/60">{event.choiceB.effect}</p>
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default App;

import React, { useState, useMemo, useCallback } from 'react';
import { GameState, ClanMember, Realm, TaskType, DevelopmentPlan, CultivationMethod, MethodType, TalentTier, RootGrade, SpecializedTalents } from '../types';
import { 
    TASK_INFO, REALM_ORDER, DEVELOPMENT_PLANS, CULTIVATION_METHODS, POSITIONS, 
    PHYSIQUE_DETAILS, ABILITY_DETAILS, getArtisanTitle, getArtisanBonus, 
    getWeaponMasteryTitle, getWeaponTalentBonus, 
    WEAPON_DETAILS, PILL_DETAILS, HERB_DETAILS, MINERAL_DETAILS, METHOD_DETAILS,
    GENERATIONS
} from '../constants';

interface Props {
    state: GameState;
    onUpdateMember: (id: string, updates: Partial<ClanMember>) => void;
    onAddMember: () => void;
}

const ITEMS_PER_PAGE = 8;

const ClanDashboard: React.FC<Props> = ({ state, onUpdateMember, onAddMember }) => {
    const [selectedMemberId, setSelectedMemberId] = useState<string | null>(null);
    const [activeTab, setActiveTab] = useState<'alive' | 'deceased'>('alive');
    const [currentPage, setCurrentPage] = useState(0);
    const [detailTab, setDetailTab] = useState<'attr' | 'talents' | 'tasks' | 'cultivation' | 'plan' | 'bag' | 'relations'>('attr');
    const [bagSubTab, setBagSubTab] = useState<'equipment' | 'pills' | 'materials' | 'methods'>('equipment');

    const [focusedSlot, setFocusedSlot] = useState<string | null>(null);
    const [focusedEquipSlot, setFocusedEquipSlot] = useState<string | null>(null);
    const [focusedBagItem, setFocusedBagItem] = useState<string | null>(null);
    const [useQuantity, setUseQuantity] = useState<number>(1);
    const [focusedLibraryMethodId, setFocusedLibraryMethodId] = useState<number | null>(null);

    // Breakthrough Modal state
    const [showBreakthroughModal, setShowBreakthroughModal] = useState(false);
    const [selectedBreakthroughPill, setSelectedBreakthroughPill] = useState<string | null>(null);

    // Tooltip State
    const [tooltip, setTooltip] = useState<{
        content: React.ReactNode;
        x: number;
        y: number;
        visible: boolean;
    } | null>(null);

    const selectedMember = useMemo(() => 
        state.members.find(m => m.id === selectedMemberId), 
    [state.members, selectedMemberId]);

    const [libraryType, setLibraryType] = useState<MethodType>('Cultivation');

    const filteredMembers = useMemo(() => {
        const list = state.members.filter(m => activeTab === 'alive' ? m.status !== 'dead' : m.status === 'dead');
        return list.sort((a, b) => {
            if (activeTab === 'alive') {
                const realmDiff = REALM_ORDER.indexOf(b.realm) - REALM_ORDER.indexOf(a.realm);
                if (realmDiff !== 0) return realmDiff;
                return b.subRealm - a.subRealm;
            }
            return (b.deathYear || 0) - (a.deathYear || 0);
        });
    }, [state.members, activeTab]);

    const pagedMembers = filteredMembers.slice(currentPage * ITEMS_PER_PAGE, (currentPage + 1) * ITEMS_PER_PAGE);

    const handleTabChange = (tab: 'alive' | 'deceased') => {
        setActiveTab(tab);
        setCurrentPage(0);
        setSelectedMemberId(null);
    };

    const getTierColor = (tier: TalentTier) => {
        switch (tier) {
            case '凡人': return 'text-slate-400';
            case '平庸': return 'text-gray-300';
            case '普通': return 'text-emerald-500';
            case '超凡': return 'text-sky-500';
            case '天才': return 'text-purple-500';
            case '绝世': return 'text-amber-500 shadow-[0_0_8px_rgba(245,158,11,0.4)]';
            case '绝世天骄': return 'text-rose-500 animate-pulse font-black shadow-[0_0_12px_rgba(244,63,94,0.6)]';
            default: return 'text-gray-400';
        }
    };

    const getTitleColor = (tier: TalentTier) => {
        switch (tier) {
            case '凡人': return 'text-white';
            case '平庸': return 'text-green-500';
            case '普通': return 'text-blue-400';
            case '超凡': return 'text-purple-500';
            case '天才': return 'text-orange-500';
            case '绝世': return 'text-amber-400';
            case '绝世天骄': return 'text-red-600';
            default: return 'text-white';
        }
    };

    const getRootGradeColor = (grade: RootGrade) => {
        switch (grade) {
            case '凡人': return 'text-slate-500';
            case '伪灵根': return 'text-gray-400';
            case '下品灵根': return 'text-emerald-600';
            case '中品灵根': return 'text-sky-600';
            case '极品灵根': return 'text-amber-600 font-bold';
            default: return 'text-gray-400';
        }
    };

    const getGradeColor = (grade: number | string | undefined) => {
        if (typeof grade === 'string') return 'border-purple-500 text-purple-400 shadow-[0_0_5px_rgba(168,85,247,0.3)]';
        const g = Number(grade) || 0;
        if (g <= 1) return 'border-slate-300 text-slate-100 bg-slate-500/10 shadow-[0_0_5px_rgba(255,255,255,0.1)]';
        if (g <= 4) return 'border-emerald-500 text-emerald-400 bg-emerald-500/10 shadow-[0_0_8px_rgba(16,185,129,0.2)]';
        if (g <= 6) return 'border-sky-500 text-sky-400 bg-sky-500/10 shadow-[0_0_10px_rgba(14,165,233,0.3)]';
        if (g === 7) return 'border-orange-500 text-orange-400 bg-orange-500/10 shadow-[0_0_12px_rgba(249,115,22,0.4)]';
        if (g >= 8) return 'border-yellow-500 text-yellow-400 bg-yellow-500/10 shadow-[0_0_15_rgba(234,179,8,0.5)]';
        return 'border-slate-400 text-slate-300';
    };

    const getRealmStyle = (realm: Realm) => {
        if (realm === Realm.Mortal) return "border-[#4a3728] bg-[#2c1810] text-[#8c6b4f]";
        return "border-[#6b4e31] bg-[#3d2b1f] text-[#c9a063]";
    };

    const getRealmText = (realm: Realm, subRealm: number) => {
        if (realm === Realm.Mortal) return '凡人';
        return `${realm}${subRealm}层`;
    };

    const getGradeText = (method: CultivationMethod) => {
        const numerals = ['','一','二','三','四','五','六','七','八','九'];
        return `${numerals[method.grade]}品${method.quality}`;
    };

    const toggleMethod = (methodId: number, type: MethodType) => {
        if (!selectedMember) return;

        if (type === 'Cultivation') {
            onUpdateMember(selectedMember.id, { mainMethodId: selectedMember.mainMethodId === methodId ? null : methodId });
        } else if (type === 'Movement') {
            onUpdateMember(selectedMember.id, { movementMethodId: selectedMember.movementMethodId === methodId ? null : methodId });
        } else if (type === 'Combat') {
            const currentAux = selectedMember.auxMethodIds;
            if (currentAux.includes(methodId)) {
                onUpdateMember(selectedMember.id, { auxMethodIds: currentAux.filter(mid => mid !== methodId) });
            } else if (currentAux.length < 4) {
                onUpdateMember(selectedMember.id, { auxMethodIds: [...currentAux, methodId] });
            }
        }
        setFocusedSlot(null);
        setFocusedLibraryMethodId(null);
    };

    const getElementColorClass = (key: string, val: number) => {
        if (val === 0) return 'text-gray-600 border-gray-800 opacity-30';
        switch (key) {
            case 'gold': return 'text-yellow-400 border-yellow-500 bg-yellow-500/10';
            case 'wood': return 'text-green-400 border-green-500 bg-green-500/10';
            case 'water': return 'text-blue-400 border-blue-500 bg-blue-500/10';
            case 'fire': return 'text-red-400 border-red-500 bg-red-500/10';
            case 'earth': return 'text-orange-700 border-orange-800 bg-orange-800/10';
            default: return 'text-gray-400 border-gray-500';
        }
    };

    const getElementName = (key: string) => {
        switch (key) {
            case 'gold': return '金';
            case 'wood': return '木';
            case 'water': return '水';
            case 'fire': return '火';
            case 'earth': return '土';
            default: return key;
