    const handleUnequip = (slot: keyof ClanMember['equippedItems']) => {
        if (!selectedMember) return;
        const itemName = selectedMember.equippedItems[slot];
        if (!itemName) return;

        const newEquipped = { ...selectedMember.equippedItems, [slot]: null };
        const newInventory = { ...selectedMember.personalInventory };

        if (slot === 'weapon') {
            newInventory.weapons[itemName] = (newInventory.weapons[itemName] || 0) + 1;
        } else {
            newInventory.weapons[itemName] = (newInventory.weapons[itemName] || 0) + 1;
        }

        onUpdateMember(selectedMember.id, { 
            equippedItems: newEquipped,
            personalInventory: newInventory
        });
        setFocusedEquipSlot(null);
    };

    const handleEquip = (itemName: string, category: 'weapon' | 'armor' | 'accessory' | 'treasure') => {
        if (!selectedMember) return;

        const newEquipped = { ...selectedMember.equippedItems };
        const newInventory = { ...selectedMember.personalInventory };

        const currentItem = newEquipped[category];
        if (currentItem) {
            newInventory.weapons[currentItem] = (newInventory.weapons[currentItem] || 0) + 1;
        }

        if (newInventory.weapons[itemName] > 0) {
            newInventory.weapons[itemName]--;
            if (newInventory.weapons[itemName] === 0) delete newInventory.weapons[itemName];
        }

        newEquipped[category] = itemName;

        onUpdateMember(selectedMember.id, { 
            equippedItems: newEquipped,
            personalInventory: newInventory
        });
        setFocusedBagItem(null);
    };

    const handleUsePill = (pillName: string, quantity: number) => {
        if (!selectedMember) return;

        const pillData = PILL_DETAILS[pillName];
        if (!pillData) return;

        const newInventory = { ...selectedMember.personalInventory };
        const currentCount = newInventory.pills[pillName] || 0;
        if (currentCount < quantity) return;

        newInventory.pills[pillName] -= quantity;
        if (newInventory.pills[pillName] === 0) delete newInventory.pills[pillName];

        const updates: Partial<ClanMember> = { personalInventory: newInventory };

        const pillEffects = (pillData as any).effects;
        if (pillEffects) {
            if (pillEffects.cultivationProgress) {
                updates.cultivationProgress = Math.min(100, (selectedMember.cultivationProgress || 0) + (pillEffects.cultivationProgress * quantity));
            }
            if (pillEffects.status) {
                updates.status = pillEffects.status;
            }
            if (pillEffects.maxAge) {
                updates.maxAge = (selectedMember.maxAge || 0) + (pillEffects.maxAge * quantity);
            }
            if (pillEffects.divineSense) {
                updates.divineSense = (selectedMember.divineSense || 0) + (pillEffects.divineSense * quantity);
            }
        }

        onUpdateMember(selectedMember.id, updates);
        setFocusedBagItem(null);
        setUseQuantity(1);
        hideTooltip();
    };

    const handleBreakthrough = () => {
        if (!selectedMember) return;

        const nextRealmIdx = REALM_ORDER.indexOf(selectedMember.realm) + 1;
        if (nextRealmIdx >= REALM_ORDER.length) return;

        // Calculate probability
        let prob = 20 + (selectedMember.aptitude / 5); // 20% base + up to 20% from aptitude

        if (selectedBreakthroughPill) {
            const pill = PILL_DETAILS[selectedBreakthroughPill];
            if (pill && (pill as any).effects?.breakthroughBonus) {
                prob += (pill as any).effects.breakthroughBonus;
            }
        }

        const roll = Math.random() * 100;
        const success = roll <= prob;

        const updates: Partial<ClanMember> = {};

        // Consume pill if used
        if (selectedBreakthroughPill) {
            const newInventory = { ...selectedMember.personalInventory };
            newInventory.pills[selectedBreakthroughPill] -= 1;
            if (newInventory.pills[selectedBreakthroughPill] === 0) delete newInventory.pills[selectedBreakthroughPill];
            updates.personalInventory = newInventory;
        }

        if (success) {
            updates.realm = REALM_ORDER[nextRealmIdx];
            updates.subRealm = 1;
            updates.cultivationProgress = 0;
            updates.maxAge = selectedMember.maxAge + 100;
            alert(`【突破成功】恭喜 ${selectedMember.name} 成功突破至 ${updates.realm} 境界！`);
        } else {
            updates.subRealm = Math.max(1, selectedMember.subRealm - 1);
            updates.cultivationProgress = 50;
            alert(`【突破失败】${selectedMember.name} 冲击境界失败，道心受损，修为跌落至 ${selectedMember.realm}${updates.subRealm}层。`);
        }

        onUpdateMember(selectedMember.id, updates);
        setShowBreakthroughModal(false);
        setSelectedBreakthroughPill(null);
    };

