                                        className={`p-2 sm:p-3 rounded-lg border transition-all cursor-pointer relative flex flex-col items-center justify-between aspect-[4/5] shadow-md group overflow-hidden
                                            ${getGradeColor(method.grade)} 
                                            ${isEquipped ? 'opacity-40 cursor-default grayscale border-gray-800 bg-black/60 shadow-none' : 'hover:scale-[1.03] active:scale-95 bg-black/70 hover:bg-black/90'}`}
                                    >
                                        <div className="text-xl sm:text-2xl mt-1 opacity-90 group-hover:scale-110 transition-transform relative z-10">📜</div>
                                        <div className="text-center mt-1.5 flex-1 flex flex-col justify-center overflow-hidden w-full relative z-10">
                                            <p className="text-[9px] sm:text-[10px] font-bold text-gray-100 leading-tight px-0.5 truncate">{method.name}</p>
                                        </div>
                                        {isEquipped && (
                                            <div className="absolute inset-0 bg-black/20 flex items-center justify-center pointer-events-none z-20">
                                                <div className="bg-gray-800/90 text-white text-[7px] px-1.5 py-0.5 rounded-sm border border-white/10 rotate-[12deg] shadow-lg font-bold">
                                                    已修习
                                                </div>
                                            </div>
                                        )}
                                    </div>
                                );
                            })}
                        </div>
                    </div>
                </div>
            </div>
        );
    };

    const renderBreakthroughModal = () => {
        if (!selectedMember) return null;

        const nextRealmIdx = REALM_ORDER.indexOf(selectedMember.realm) + 1;
        const nextRealm = REALM_ORDER[nextRealmIdx];

        // Find available breakthrough pills in member's inventory
        const availablePills = Object.keys(selectedMember.personalInventory.pills).filter(name => {
            const pill = PILL_DETAILS[name];
            return pill && (pill as any).effects?.breakthroughBonus !== undefined;
        });

        const baseProb = 20 + (selectedMember.aptitude / 5);
        let bonusProb = 0;
        if (selectedBreakthroughPill) {
            const pill = PILL_DETAILS[selectedBreakthroughPill];
            bonusProb = (pill as any).effects?.breakthroughBonus || 0;
        }
        const totalProb = Math.min(100, baseProb + bonusProb);

        return (
            <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/80 backdrop-blur-md animate-fade-in p-4">
                <div className="bg-[#1a1412] border-4 border-yellow-900/40 p-6 rounded-lg w-full max-w-md shadow-2xl">
                    <h3 className="text-2xl font-cursive text-yellow-500 text-center mb-6">冲击 {nextRealm} 境界</h3>

                    <div className="bg-black/40 p-4 rounded border border-white/5 mb-6">
                        <div className="flex justify-between items-center mb-2">
                            <span className="text-gray-500 text-sm">基础成功率</span>
                            <span className="text-yellow-400 font-bold">{baseProb.toFixed(1)}%</span>
                        </div>
                        <div className="flex justify-between items-center mb-2">
                            <span className="text-gray-500 text-sm">灵丹加成</span>
                            <span className="text-emerald-400 font-bold">+{bonusProb}%</span>
                        </div>
                        <div className="border-t border-white/10 pt-2 flex justify-between items-center">
                            <span className="text-gray-300 font-bold">总计成功率</span>
                            <span className="text-2xl text-yellow-500 font-black">{totalProb.toFixed(1)}%</span>
                        </div>
                    </div>

                    <div className="mb-6">
                        <p className="text-xs text-gray-500 mb-3 uppercase tracking-widest font-bold">选择辅助灵丹</p>
                        <div className="grid grid-cols-2 gap-2">
                            <button 
                                onClick={() => setSelectedBreakthroughPill(null)}
                                className={`p-2 rounded border text-[10px] font-bold transition-all ${selectedBreakthroughPill === null ? 'bg-yellow-900/20 border-yellow-500 text-yellow-100' : 'bg-black/40 border-white/5 text-gray-500'}`}
                            >
                                无
                            </button>
                            {availablePills.map(name => (
                                <button 
                                    key={name}
                                    onClick={() => setSelectedBreakthroughPill(name)}
                                    className={`p-2 rounded border text-[10px] font-bold transition-all ${selectedBreakthroughPill === name ? 'bg-emerald-900/20 border-emerald-500 text-emerald-100' : 'bg-black/40 border-white/5 text-gray-400'}`}
                                >
                                    {name} (+{(PILL_DETAILS[name] as any).effects.breakthroughBonus}%)
                                </button>
                            ))}
                        </div>
                        {availablePills.length === 0 && <p className="text-[10px] text-red-900/60 mt-2 italic text-center">囊中无突破灵丹</p>}
                    </div>

                    <div className="bg-red-900/10 border border-red-900/20 p-3 rounded mb-6">
                        <p className="text-[10px] text-red-500 leading-relaxed font-bold">⚠️ 警示：突破境界凶险异常。若失败，修为将跌落至本境界第8层，且道基受损。</p>
                    </div>

                    <div className="flex gap-4">
                        <button 
                            onClick={() => { setShowBreakthroughModal(false); setSelectedBreakthroughPill(null); }}
                            className="flex-1 py-3 bg-gray-800 hover:bg-gray-700 text-white rounded font-bold text-sm transition-all"
                        >
                            退下
                        </button>
                        <button 
                            onClick={handleBreakthrough}
                            className="flex-1 py-3 bg-yellow-700 hover:bg-yellow-600 text-white rounded font-bold text-sm shadow-lg shadow-yellow-900/20 transition-all"
                        >
                            开始突破
                        </button>
                    </div>
                </div>
            </div>
        );
    };

    const renderBagItem = (icon: string, name: string, count: number, bgClass: string, borderClass: string, hoverBorderClass: string, onAction?: (qty: number) => void, actionLabel?: string) => (
        <div 
            key={name} 
            onClick={() => {
                if (focusedBagItem === name) {
                    setFocusedBagItem(null);
                    setUseQuantity(1);
                } else {
                    setFocusedBagItem(name);
                    setUseQuantity(1);
                }
            }}
            onMouseEnter={(e) => showTooltip(e, renderItemTooltipContent(name))}
            onMouseLeave={hideTooltip}
            className={`${bgClass} border ${borderClass} p-3 rounded-lg flex flex-col items-center group ${hoverBorderClass} transition-all aspect-[4/5] justify-between shadow-lg relative overflow-hidden`}>
            <div className="text-3xl mt-2 group-hover:scale-110 transition-transform">{icon}</div>
            <span className="text-[12px] text-white font-bold text-center truncate w-full mt-2 px-1">{name}</span>
            <div className="mt-auto">
                <span className="text-[11px] font-bold text-[#f59e0b] mt-auto">数量：{count}</span>
            </div>

            {onAction && focusedBagItem === name && (
                <div className="absolute inset-0 bg-black/90 flex flex-col items-center justify-center z-10 animate-fade-in p-2">
                    {count > 1 && (
                        <div className="flex items-center gap-1 mb-2 bg-black/60 p-1 rounded-md border border-yellow-900/30">
                            <button 
                                onClick={(e) => { e.stopPropagation(); setUseQuantity(Math.max(1, useQuantity - 1)); }}
                                className="w-6 h-6 flex items-center justify-center bg-yellow-900/20 text-yellow-500 rounded hover:bg-yellow-900/40 text-xs font-bold"
                            >
                                -
                            </button>
                            <input 
                                type="number" 
                                value={useQuantity} 
                                onChange={(e) => setUseQuantity(Math.min(count, Math.max(1, parseInt(e.target.value) || 1)))}
                                onClick={(e) => e.stopPropagation()}
                                className="w-8 bg-transparent text-center text-xs text-yellow-500 outline-none font-bold [appearance:textfield] [&::-webkit-outer-spin-button]:appearance-none [&::-webkit-inner-spin-button]:appearance-none"
                            />
                            <button 
                                onClick={(e) => { e.stopPropagation(); setUseQuantity(Math.min(count, useQuantity + 1)); }}
                                className="w-6 h-6 flex items-center justify-center bg-yellow-900/20 text-yellow-500 rounded hover:bg-yellow-900/40 text-xs font-bold"
                            >
                                +
                            </button>
                        </div>
                    )}
                    <button 
                        onClick={(e) => { e.stopPropagation(); onAction(useQuantity); hideTooltip(); }}
                        className="bg-yellow-700 hover:bg-yellow-600 text-white text-[11px] py-1.5 px-3 rounded font-bold shadow-lg w-full"
                    >
                        {actionLabel || '操作'} {useQuantity > 1 ? `x${useQuantity}` : ''}
                    </button>
                </div>
            )}
        </div>
    );

    return (
        <div className="bg-[#1e130c] border-l-4 border-yellow-800 h-full flex flex-col relative overflow-hidden font-serif shadow-2xl">
            {tooltip && tooltip.visible && (
                <div 
                    className="fixed z-[10000] pointer-events-none bg-black/95 border-2 border-yellow-900/50 p-4 rounded shadow-[0_10px_40px_rgba(0,0,0,0.8)] backdrop-blur-md animate-fade-in"
                    style={{ 
                        left: tooltip.x, 
                        top: tooltip.y, 
                        transform: `translate(-50%, ${tooltip.y > window.innerHeight / 2 ? '-100%' : '0'})` 
                    }}
                >
                    {tooltip.content}
                </div>
            )}

            {showBreakthroughModal && renderBreakthroughModal()}

            <div className="p-4 border-b border-yellow-900/30 bg-black/40 shrink-0">
                <div className="flex justify-between items-center mb-4">
                    <h2 className="text-xl font-cursive text-yellow-500">⛩️ 族谱常青</h2>
                </div>
                <div className="flex p-1 bg-black/40 rounded-lg gap-1 border border-yellow-900/10">
                    <button onClick={() => handleTabChange('alive')} className={`flex-1 py-1.5 text-xs rounded transition-all ${activeTab === 'alive' ? 'bg-yellow-800 text-yellow-100 shadow-lg' : 'text-gray-500 hover:text-gray-300'}`}>在世族人</button>
                    <button onClick={() => handleTabChange('deceased')} className={`flex-1 py-1.5 text-xs rounded transition-all ${activeTab === 'deceased' ? 'bg-gray-800 text-gray-100' : 'text-gray-500 hover:text-gray-300'}`}>英灵祠堂</button>
                </div>
            </div>

            <div className="flex-1 overflow-y-auto p-4 space-y-2 custom-scrollbar">
                {pagedMembers.length > 0 ? pagedMembers.map(member => (
                    <div 
                        key={member.id} onClick={() => activeTab === 'alive' && setSelectedMemberId(member.id)}
                        className={`group p-3 rounded-md border transition-all cursor-pointer animate-fade-in ${selectedMemberId === member.id ? 'bg-[#2d1e15] border-yellow-600 scale-[1.02] shadow-xl' : 'bg-[#1e130c] border-yellow-900/30 hover:border-yellow-700/50'}`}
                    >
                        <div className="flex justify-between items-start mb-1">
                            <div className="flex items-center gap-2">
                                <span className="font-bold text-sm text-yellow-100/90">{member.name}</span>
                            </div>
                            <button className={`text-[9px] px-2 py-0.5 rounded border shadow-sm hover:brightness-125 transition-all ${getRealmStyle(member.realm)}`}>
                                {getRealmText(member.realm, member.subRealm)}
                            </button>
                        </div>
                        <div className="flex justify-between text-[10px] text-gray-500 items-baseline">
                            <span>评级：<span className={`font-black ${getTierColor(member.tier)}`}>{member.tier}</span></span>
                        </div>
                        {activeTab === 'alive' && member.realm !== Realm.Mortal && (
                            <div className="mt-2 w-full h-1 bg-black/40 rounded-full overflow-hidden border border-white/5">
                                <div 
                                    className={`h-full transition-all duration-1000 ${member.subRealm === 9 && member.cultivationProgress >= 100 ? 'bg-red-600 shadow-[0_0_8px_rgba(220,38,38,0.8)]' : 'bg-blue-500/60'}`} 
                                    style={{ width: `${member.cultivationProgress}%` }}
                                ></div>
                            </div>
                        )}
                    </div>
                )) : (
                    <div className="py-20 text-center text-gray-700 opacity-40 italic">空空如也</div>
                )}
            </div>

            {selectedMember && activeTab === 'alive' && (
                <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/95 p-2 sm:p-4 font-serif overflow-hidden">
                    <div className="relative w-full max-w-6xl max-h-[95vh] h-full bg-[#1a2521] border-[4px] sm:border-[12px] border-[#2c3e34] rounded-sm shadow-2xl overflow-hidden flex flex-col">
                        <div className="h-20 sm:h-24 bg-[#141e1b] border-b border-[#2c3e34] flex items-center px-2 sm:px-8 shrink-0 pt-2">
                            <div className="flex items-center gap-1 sm:gap-2 h-full overflow-x-auto scrollbar-hide">
                                <button onClick={() => setDetailTab('attr')} className={`whitespace-nowrap px-3 sm:px-4 h-full flex items-center text-[11px] sm:text-sm transition-all border-b-4 font-bold ${detailTab === 'attr' ? 'border-yellow-500 text-yellow-500 bg-yellow-900/10' : 'border-transparent text-gray-500 hover:text-gray-300'}`}>👤 属性</button>
                                <button onClick={() => setDetailTab('cultivation')} className={`whitespace-nowrap px-3 sm:px-4 h-full flex items-center text-[11px] sm:text-sm transition-all border-b-4 font-bold ${detailTab === 'cultivation' ? 'border-yellow-500 text-yellow-500 bg-yellow-900/10' : 'border-transparent text-gray-500 hover:text-gray-300'}`}>🌀 功法</button>
                                <button onClick={() => setDetailTab('bag')} className={`whitespace-nowrap px-3 sm:px-4 h-full flex items-center text-[11px] sm:text-sm transition-all border-b-4 font-bold ${detailTab === 'bag' ? 'border-yellow-500 text-yellow-500 bg-yellow-900/10' : 'border-transparent text-gray-500 hover:text-gray-300'}`}>🎒 行囊</button>
                                <button onClick={() => setDetailTab('tasks')} className={`whitespace-nowrap px-3 sm:px-4 h-full flex items-center text-[11px] sm:text-sm transition-all border-b-4 font-bold ${detailTab === 'tasks' ? 'border-yellow-500 text-yellow-500 bg-yellow-900/10' : 'border-transparent text-gray-500 hover:text-gray-300'}`}>🎯 指派</button>
                            </div>
                            <button onClick={() => setSelectedMemberId(null)} className="ml-auto min-w-[36px] w-9 h-9 bg-red-900/20 hover:bg-red-900/40 text-red-500 rounded-full flex items-center justify-center text-xl transition-all font-bold">×</button>
                        </div>

                        <div className="flex-1 flex flex-col sm:flex-row overflow-hidden">
                            <div className="w-full sm:w-[35%] lg:w-[38%] flex flex-col items-center justify-start border-r border-[#2c3e34] p-4 sm:p-8 bg-black/10 shrink-0 pt-8 sm:pt-10 overflow-y-auto custom-scrollbar">
                                <div className="mb-6 w-full flex justify-center scale-90 sm:scale-100">
                                    {renderNamePlaque(selectedMember)}
                                </div>
                                <div className="relative flex items-center justify-center gap-4 sm:gap-6 py-4">
                                    <div className="w-28 h-40 lg:w-44 lg:h-64 bg-black/40 rounded-full border-2 border-yellow-900/20 relative flex items-center justify-center">
                                        <div className="text-6xl lg:text-8xl opacity-10">🧘</div>
                                    </div>
                                </div>

                                <div className="mt-4 text-center">
                                    <p className="text-xl sm:text-2xl font-bold text-blue-500 tracking-widest">
                                        {getRealmText(selectedMember.realm, selectedMember.subRealm)}
                                    </p>
                                </div>

                                <div className="w-full mt-8 p-3 bg-black/30 border border-yellow-900/10 rounded">
                                    <div className="flex justify-between items-center mb-2">
                                        <h4 className="text-[10px] text-gray-500 font-bold uppercase">灵力状态</h4>
                                        {selectedMember.subRealm === 9 && selectedMember.cultivationProgress >= 100 && (
                                            <button 
                                                onClick={() => setShowBreakthroughModal(true)}
                                                className="text-[10px] px-2 py-0.5 bg-red-900/40 border border-red-500 text-red-400 rounded hover:bg-red-700 hover:text-white transition-all animate-pulse"
                                            >
                                                ⚡ 寻求突破
                                            </button>
                                        )}
                                    </div>
                                    <div className="w-full h-2 bg-gray-900 rounded-full overflow-hidden border border-white/10">
                                        <div 
                                            className={`h-full transition-all duration-1000 ${selectedMember.subRealm === 9 && selectedMember.cultivationProgress >= 100 ? 'bg-red-600 shadow-[0_0_8px_rgba(220,38,38,0.8)]' : 'bg-blue-600 shadow-[0_0_8px_rgba(37,99,235,0.6)]'}`} 
                                            style={{ width: `${selectedMember.cultivationProgress}%` }}
                                        ></div>
                                    </div>
                                </div>
                            </div>

                            <div className="flex-1 p-4 sm:p-8 lg:p-10 overflow-hidden bg-[#1a2521]/50 flex flex-col min-h-0">
                                <div className="flex-1 min-h-0">
                                    {detailTab === 'attr' && (
                                        <div className="h-full overflow-y-auto custom-scrollbar space-y-10 animate-fade-in pr-2">
                                            <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                                                <div>
                                                    <h4 className="text-yellow-600 text-[15px] font-bold uppercase tracking-[0.3em] border-b border-yellow-900/20 pb-2 mb-6">基础属性</h4>
                                                    <div className="grid grid-cols-2 gap-y-4 gap-x-6 text-sm">
                                                        <div className="flex justify-between border-b border-white/5 pb-2">
                                                            <span className="text-gray-500">年龄：</span>
                                                            <span className="text-gray-200 font-bold">{selectedMember.age} 岁</span>
                                                        </div>
                                                        <div className="flex justify-between border-b border-white/5 pb-2">
                                                            <span className="text-gray-500">寿元：</span>
                                                            <span className={`font-bold ${selectedMember.maxAge - selectedMember.age < 10 ? 'text-red-500 animate-pulse' : 'text-green-500'}`}>
                                                                {selectedMember.age} / {selectedMember.maxAge} 载
                                                            </span>
                                                        </div>
                                                        <div className="flex justify-between border-b border-white/5 pb-2">
                                                            <span className="text-gray-500">评价：</span>
                                                            <span className={`font-black px-2 rounded-sm bg-black/30 border border-white/5 ${getTierColor(selectedMember.tier)}`}>{selectedMember.tier}</span>
                                                        </div>
                                                    </div>
                                                </div>
                                                <div>
                                                    <h4 className="text-blue-600 text-[15px] font-bold uppercase tracking-[0.3em] border-b border-blue-900/20 pb-2 mb-6">修行天赋</h4>
                                                    <div className="grid grid-cols-2 gap-y-4 gap-x-6 text-sm">
                                                        <div className="flex justify-between border-b border-white/5 pb-2">
                                                            <span className="text-gray-500">资质：</span>
                                                            <span className="text-yellow-500 font-bold">{selectedMember.aptitude}</span>
                                                        </div>
                                                        <div className="flex justify-between border-b border-white/5 pb-2">
                                                            <span className="text-gray-500">体质：</span>
                                                            <span className="text-pink-500 font-bold">{selectedMember.physique}</span>
                                                        </div>
                                                    </div>
                                                </div>
                                            </div>
                                        </div>
                                    )}

                                    {detailTab === 'bag' && (
                                        <div className="h-full overflow-y-auto custom-scrollbar space-y-8 animate-fade-in pr-2">
                                            <div className="flex flex-wrap gap-2 p-1 bg-black/40 rounded-xl border border-yellow-900/20 w-fit">
                                                <button onClick={() => setBagSubTab('pills')} className={`px-4 sm:px-6 py-2 text-xs rounded-lg transition-all font-bold ${bagSubTab === 'pills' ? 'bg-pink-900/40 text-pink-200' : 'text-gray-500 hover:text-gray-300'}`}>💊 丹药</button>
                                            </div>

                                            <div className="grid grid-cols-2 sm:grid-cols-4 lg:grid-cols-5 gap-4">
                                                {bagSubTab === 'pills' && (
                                                    Object.entries(selectedMember.personalInventory.pills).length > 0 ? Object.entries(selectedMember.personalInventory.pills).map(([name, count]) => 
                                                        renderBagItem('💊', name, count, 'bg-[#1a1215]', 'border-[#4d1d2d]', 'hover:border-[#ff3870]', (qty) => handleUsePill(name, qty), '服用')
                                                    ) : <div className="col-span-full py-24 text-center text-gray-700 italic border-2 border-dashed border-white/5 rounded-xl">尚未携带任何灵丹</div>
                                                )}
                                            </div>
                                        </div>
                                    )}

                                    {detailTab === 'cultivation' && renderCultivationTab()}

                                    {detailTab === 'tasks' && (
                                        <div className="h-full overflow-y-auto custom-scrollbar space-y-3 animate-fade-in max-w-2xl mx-auto pr-2">
                                            {(Object.keys(TASK_INFO) as TaskType[]).map(task => (
                                                <button
                                                    key={task}
                                                    onClick={() => onUpdateMember(selectedMember.id, { assignment: task })}
                                                    className={`w-full p-6 rounded-2xl border transition-all text-left shadow-lg ${selectedMember.assignment === task ? 'bg-yellow-900/20 border-yellow-500 text-yellow-100 ring-1 ring-yellow-500/50' : 'bg-black/30 border-white/5 hover:bg-black/50 hover:border-white/20 text-gray-400'}`}
                                                >
                                                    <p className="text-base font-bold mb-1">{TASK_INFO[task].label}</p>
                                                    <p className="text-xs opacity-60 leading-relaxed">{TASK_INFO[task].desc}</p>
                                                </button>
                                            ))}
                                        </div>
                                    )}
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default ClanDashboard;
